+        mgr.close_session("ext-a", "s1", &mut cx).unwrap();
+        mgr.unload_extension("ext-a", &mut cx).unwrap();
+        (
+            mgr.loaded_extension_count(),
+            mgr.is_extension_running("ext-a"),
+            mgr.is_extension_running("ext-b"),
